#include <bits/stdc++.h>
using namespace std;
int n,a[10004],sum[1000006],ans[10004];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j*j<=a[i];j++)
            if(a[i]%j==0)
                sum[j]++,sum[a[i]/j]+=(j!=a[i]/j);
    for(int i=1;i<=1000000;i++)
        ans[sum[i]]=i;
    for(int i=n-1;i;i--)
        ans[i]=max(ans[i],ans[i+1]);
    for(int i=1;i<=n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
